const clients = [
  { project: 'aarohaom', domain: 'aarohaom.com' },
  { project: 'blackpanda', domain: 'blackpandaenterprises.com' },
  { project: 'ageddentistry', domain: 'ageddentistry.org' }
];
return clients.map(c => ({ json: c }));

const apiData = $input.item.json;
const clientData = $('Define Client Domains').item.json;

const taskResult = apiData.tasks?.[0]?.result?.[0] || {};

const totalBacklinks = taskResult.backlinks || 0;
const referringDomains = taskResult.referring_domains || 0;
const domainRank = taskResult.rank || 0;

// Store individual backlinks for tracking
const newLinks = taskResult.items || [];

return [{ json: {
  project: clientData.project,
  domain: clientData.domain,
  totalBacklinks,
  referringDomains,
  domainRank,
  newLinks: newLinks.slice(0, 20), // Top 20 to store
  checkedAt: new Date().toISOString()
}}];

// Aggregate into weekly backlink summary
const allItems = $input.all();
const data = allItems.map(i => i.json);

let msg = `*🔗 Weekly Backlink Report — ${new Date().toDateString()}*\n\n`;

data.forEach(d => {
  msg += `*${d.project}*: ${d.totalBacklinks} total backlinks | ${d.referringDomains} referring domains\n`;
  msg += `  Domain Rank: ${d.domainRank}\n`;
});

msg += `\n_New backlinks stored in database. Check \`backlink_data\` table for details._`;

return [{ json: { summaryText: msg } }];
